object AuthInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val newRequestBuilder = originalRequest.newBuilder().header("Authorization", "Bearer YOUR_TOKEN")
        val newRequest = newRequestBuilder.build()
        return chain.proceed(newRequest)
    }
}

private const val CONNECT_TIMEOUT = 15
private const val READ_TIMEOUT = 20

val client: OkHttpClient by lazy {
    OkHttpClient.Builder()
        .connectTimeout(CONNECT_TIMEOUT.toLong(), TimeUnit.SECONDS)
        .readTimeout(READ_TIMEOUT.toLong(), TimeUnit.SECONDS)
        .addInterceptor(AuthInterceptor())
        .build()
}

val apiService: UserService by lazy {
    val retrofit = Retrofit.Builder()
        .client(client)
        .baseUrl(PRODUCTION_API_URL) // default environment
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    retrofit.create(UserService::class.java)
}

fun getUserProfile(userId: Int): Call<User> {
    return apiService.getUserProfile(userId).execute().request()
